nta.declaration:
// Global Declarations
const int N=5;
const int StableLeaderHeartbeatCount = 100;

// Upper and lower bounds for election (ET) and heartbeat (HB) timeouts
const int ETL=5;
const int ETU=10;
const int HBL=1;
const int HBU=2;

// the term according to the RPC broadcaster
int heartbeatTerm;
int heartbeatCounter;
int requestVoteTerm;

// id of vote requester
int[0,N] requesterId;

broadcast chan stable;

// RPCs
broadcast chan requestVote;
broadcast chan heartbeat;

// Votes for each candidate
int[0,N] votes[N];

int max(int a, int b) {
    return (a > b) ? a : b;
}

template.declaration:
// Local Declarations
clock timer;
int currentTerm;
int timeout = -1;
// id of the candidate this node has voted for in the current term
int voted = false;

nta.system:
// System Declarations
const int C_RED    = 0;
const int C_YELLOW = 6;
const int C_GREEN  = 1;

node0 := Node(0);
node1 := Node(1);
node2 := Node(2);
node3 := Node(3);
node4 := Node(4);


// Nodes part of the system
system node0, node1, node2, node3, node4;

gantt {
    node0:
      node0.Follower  -> C_RED,
      node0.Candidate -> C_YELLOW,
      node0.Leader    -> C_GREEN;

    node1:
      node1.Follower  -> C_RED,
      node1.Candidate -> C_YELLOW,
      node1.Leader    -> C_GREEN;

    node2:
      node2.Follower  -> C_RED,
      node2.Candidate -> C_YELLOW,
      node2.Leader    -> C_GREEN;

    node3:
      node3.Follower  -> C_RED,
      node3.Candidate -> C_YELLOW,
      node3.Leader    -> C_GREEN;

    node4:
      node4.Follower  -> C_RED,
      node4.Candidate -> C_YELLOW,
      node4.Leader    -> C_GREEN;
}
